(()=>{"use strict";self.addEventListener("push",t=>{let i;if(t.data){try{i=t.data.json()}catch{i={title:"Mandarin Coach",body:t.data.text()}}t.waitUntil(self.registration.showNotification(i.title??"Mandarin Coach",{body:i.body,icon:i.icon??"/icons/icon-192.png",badge:i.badge??"/icons/icon-192.png",data:i.data}))}}),self.addEventListener("notificationclick",t=>{t.notification.close();let i=t.notification.data?.url??"/";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{let n=t.find(t=>t.url.includes(i));return n&&"focus"in n?n.focus():self.clients.openWindow(i)}))})})();